    15→
    16→export class InstanceMapper {
    17→	/**
    18→	 * Decrypts an object literal as received from the DB and maps it to an entity class (e.g. Mail)
    19→	 * @param model The TypeModel of the instance
    20→	 * @param instance The object literal as received from the DB
    21→	 * @param sk The session key, must be provided for encrypted instances
    22→	 * @returns The decrypted and mapped instance
    23→	 */
    24→	decryptAndMapToInstance<T>(model: TypeModel, instance: Record<string, any>, sk: Aes128Key | null): Promise<T> {
    25→		let decrypted: any = {
    26→			_type: new TypeRef(model.app, model.name),
    27→		}
    28→
    29→		for (let key of Object.keys(model.values)) {
    30→			let valueType = model.values[key]
    31→			let value = instance[key]
    32→
    33→			try {
    34→				decrypted[key] = decryptValue(key, valueType, value, sk)
    35→			} catch (e) {
    36→				if (decrypted._errors == null) {
    37→					decrypted._errors = {}
    38→				}
    39→
    40→				decrypted._errors[key] = JSON.stringify(e)
    41→				console.log("error when decrypting value on type:", `[${model.app},${model.name}]`, "key:", key)
    42→			} finally {
    43→				if (valueType.encrypted) {
    44→					if (valueType.final) {
    45→						// we have to store the encrypted value to be able to restore it when updating the instance. this is not needed for data transfer types, but it does not hurt
    46→						decrypted["_finalEncrypted_" + key] = value
