/**
 * Regression Test: Non-legacy mail content fails to decrypt
 *
 * This test demonstrates the bug where non-legacy mails fail to decrypt due to
 * missing session key propagation when loading related entities (MailDetailsBlob).
 *
 * Root cause: When loading MailDetailsBlob for non-legacy mails, the session key
 * from the parent Mail's bucketKey is not being propagated to the entity loader,
 * causing decryption to fail with "could not resolve session key" errors.
 */

import type { Mail, MailDetailsBlob, BucketKey, InstanceSessionKey, Body } from './app/src/api/entities/tutanota/TypeRefs.js'
import type { EntityClient } from './app/src/api/common/EntityClient.js'
import { createMail, createMailDetailsBlob, createBucketKey, createInstanceSessionKey, createBody } from './app/src/api/entities/tutanota/TypeRefs.js'
import { CryptoFacade } from './app/src/api/worker/crypto/CryptoFacade.js'
import { InstanceMapper } from './app/src/api/worker/crypto/InstanceMapper.js'
import { random, aes128Encrypt, aes128Decrypt } from '@tutao/tutanota-crypto'
import { uint8ArrayToBase64, base64ToUint8Array } from '@tutao/tutanota-utils'

describe('Non-legacy mail decryption regression test', () => {
	let entityClient: Partial<EntityClient>
	let cryptoFacade: CryptoFacade
	let instanceMapper: InstanceMapper
	let sessionKey: Uint8Array
	let mailDetailsId: [string, string]
	let testMail: Mail
	let testMailDetails: MailDetailsBlob

	beforeEach(async () => {
		// Generate a test session key
		sessionKey = random(16) // AES-128 key

		const mailListId = 'mailListId'
		const mailElementId = 'mailElementId'
		const detailsListId = 'detailsListId'
		const detailsElementId = 'detailsElementId'
		mailDetailsId = [detailsListId, detailsElementId]

		// Create test mail body with encrypted content
		const unencryptedBody = createBody({
			text: 'This is the secret mail body content',
			compressedText: null,
		})

		// Create test mail details blob with encrypted body
		testMailDetails = createMailDetailsBlob({
			_id: mailDetailsId,
			details: {
				body: unencryptedBody,
				recipients: null,
				replyTos: [],
				headers: null,
				authStatus: null,
				sentDate: new Date(),
			},
		})

		// Create bucket key with instance session keys
		// This is what non-legacy mails use to store session keys
		const instanceSessionKey: InstanceSessionKey = createInstanceSessionKey({
			instanceId: detailsElementId,
			instanceList: detailsListId,
			symEncSessionKey: sessionKey, // The encrypted session key for MailDetailsBlob
			typeInfo: {
				app: 'tutanota',
				name: 'MailDetailsBlob',
			},
		})

		const bucketKey: BucketKey = createBucketKey({
			_id: 'bucketKeyId',
			groupEncBucketKey: null,
			pubEncBucketKey: null,
			bucketEncSessionKeys: [instanceSessionKey],
			keyGroup: 'groupId',
		})

		// Create the mail with bucketKey (non-legacy mail structure)
		testMail = createMail({
			_id: [mailListId, mailElementId],
			subject: 'Test Non-Legacy Mail',
			body: null, // Legacy mails have this, non-legacy don't
			mailDetails: mailDetailsId, // Non-legacy: reference to details blob
			mailDetailsDraft: null,
			bucketKey: bucketKey, // Non-legacy: bucket key with instance session keys
			_ownerEncSessionKey: null, // No owner-encrypted key for non-legacy
			_ownerGroup: null,
			_permissions: 'permissionsId',
			sender: {
				name: 'Test Sender',
				address: 'sender@test.com',
				contact: null,
			},
			toRecipients: [],
			ccRecipients: [],
			bccRecipients: [],
			replyTos: [],
			attachments: [],
			state: '0',
			receivedDate: new Date(),
			sentDate: new Date(),
			unread: true,
			confidential: false,
			method: '0',
			authStatus: null,
			differentEnvelopeSender: null,
			listUnsubscribe: false,
			movedTime: null,
			phishingStatus: '0',
			recipientCount: '0',
			replyType: '0',
			restrictions: null,
			headers: null,
			conversationEntry: ['conversationListId', 'conversationElementId'],
			firstRecipient: null,
		})

		// Setup the mock entity client
		entityClient = {
			load: jest.fn(async (typeRef: any, id: any) => {
				// When loading MailDetailsBlob, it should have the session key available
				// But the bug is that it doesn't get passed through
				return testMailDetails
			}),
			loadMultiple: jest.fn(async (typeRef: any, listId: string, elementIds: string[]) => {
				// Simulate the server returning encrypted MailDetailsBlob
