	 * Maps element IDs to their session keys
	 */
	const sessionKeyCache: Record<string, Uint8Array> = {}

	/**
	 * Mock for CryptoFacade.resolveSessionKey function
	 * This simulates the actual session key resolution logic
	 */
	function mockResolveSessionKey(
		typeModel: { name: string; app: string; encrypted: boolean },
		instance: any
	): Uint8Array | null {
		if (!typeModel.encrypted) {
			return null
		}

