				{ name: 'MailBody' },
				mail.body
			)
			return { mail, body }
		} else {
			// Non-legacy path has the bug
			if (mail.mailDetailsDraft) {
				// Draft path
				const details = await mockLoad(
					{ name: 'MailDetailsDraft' },
					mail.mailDetailsDraft
				)
				return { mail, details }
			} else {
				// Received/sent mail path - uses loadMultiple
				const [listId, elementId] = mail.mailDetails
				const [mailDetailsBlob] = await mockLoadMultiple(
					{ name: 'MailDetailsBlob' },
					listId,
					[elementId]
				)
				return { mail, details: mailDetailsBlob }
			}
