	async function mockLoadMultiple(
		typeRef: any,
		listId: string,
		elementIds: string[]
	): Promise<any[]> {
		// For each element ID, create a MailDetailsBlob
		return elementIds.map((elementId) => ({
			_type: typeRef,
			_id: [listId, elementId],
			details: {
				body: {
					text: 'ENCRYPTED: Body content for batch-loaded mail',
				},
				recipients: null,
				replyTos: [],
				headers: null,
			},
		}))
