	 */
	async function loadMailDetailsSimulation(
		mail: any,
		isLegacy: boolean
	): Promise<any> {
		if (isLegacy) {
			// Legacy path works fine
			const body = await mockLoad(
				{ name: 'MailBody' },
				mail.body
			)
			return { mail, body }
		} else {
			// Non-legacy path has the bug
			if (mail.mailDetailsDraft) {
				// Draft path
				const details = await mockLoad(
					{ name: 'MailDetailsDraft' },
					mail.mailDetailsDraft
				)
				return { mail, details }
			} else {
